#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef unsigned long long uLL;
int qwq[256];inline int Popcount(const uLL &res)
{
	return qwq[res&255]+qwq[res>>8&255]+qwq[res>>16&255]+qwq[res>>24&255]
	 +qwq[res>>32&255]+qwq[res>>40&255]+qwq[res>>48&255]+qwq[res>>56&255];
}
const int N=1e5+10,NQ=33335;int n,tot,a[N],P[N],L,R,cnt[N];
inline int bnd(const int &k){int l(1),r(n),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
struct Bitset
{
	uLL a[1563];inline void clear(){memset(a,0,sizeof(a));}
	inline void ins(const int &p){a[p>>6]|=(1ull<<(p&63));}
	inline void del(const int &p){a[p>>6]^=(1ull<<(p&63));}
	inline int cnt(){int ans=0;for(int i=0;i<1563;++i)ans+=Popcount(a[i]);return ans;}
	inline void operator &= (const Bitset &Q){for(int i=0;i<1563;++i)a[i]&=Q.a[i];}
	inline void operator = (const Bitset &Q){memcpy(a,Q.a,sizeof(a));}
}ans[NQ],Ans;bool vis[N]; struct Nd{int l,r,idx;}q[N]; int sum[N];
inline void ins(const int &x){Ans.ins(x-(++cnt[x]));}
inline void del(const int &x){Ans.del(x-(cnt[x]--));}
inline void Solve()
{
	int Q=tot<=33334?tot:33334;tot-=Q;int nq=0;memset(cnt,0,(n+2)<<2);
	rep(1,Q,i)
	{
		ans[i].clear();sum[i]=0;
		q[++nq].l=read();q[nq].r=read();q[nq].idx=i;sum[i]+=(q[nq].r-q[nq].l+1);
		q[++nq].l=read();q[nq].r=read();q[nq].idx=i;sum[i]+=(q[nq].r-q[nq].l+1);
		q[++nq].l=read();q[nq].r=read();q[nq].idx=i;sum[i]+=(q[nq].r-q[nq].l+1);
	}
	std::sort(q+1,q+nq+1,[&](const Nd&x,const Nd&y){return (x.l>>8)==(y.l>>8)?(x.l>>8&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	memset(vis,0,Q+2);L=q[1].l;R=L-1;Ans.clear();rep(1,nq,i)
	{
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);
		while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		if(!vis[q[i].idx]){vis[q[i].idx]=true;ans[q[i].idx]=Ans;}else ans[q[i].idx]&=Ans;
	}
	rep(1,Q,i)printf("%d\n",sum[i]-3*ans[i].cnt());return;
}
int main()
{
	for(int i=1;i<256;++i)qwq[i]=qwq[i>>1]+(i&1);
	n=read();tot=read();rep(1,n,i)a[i]=P[i]=read();std::sort(P+1,P+n+1);rep(1,n,i)a[i]=bnd(a[i]);
	while(tot)Solve();return 0;
}
